/*
 * Probe program: prints AWS.OS_Lib package body for the host platform.
 *
 * Replaces AWS's xoscons + asm-injection pipeline. Compiles with the system
 * C compiler (any cc that handles C99). Run, redirect stdout to os_lib.ads.
 *
 *   cc -o gen_os_lib gen_os_lib.c
 *   ./gen_os_lib > os_lib.ads
 *
 * The set of constants tracks vendor/aws/config/setup/os_lib-tmplt.c. When
 * the AWS pin bumps, diff that file against this one to spot new constants.
 */

#include <errno.h>
#include <fcntl.h>
#include <limits.h>
#include <netdb.h>
#include <netinet/in.h>
#include <netinet/tcp.h>
#include <poll.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>
#include <sys/ioctl.h>
#include <sys/socket.h>
#include <sys/time.h>
#include <sys/types.h>

#define D(name, comment) \
    printf("   %-27s : constant := %d;%s%s\n", #name, (int)(name), \
           (comment[0] ? "  --  " : ""), comment)
#define U(name, comment) \
    printf("   %-27s : constant := %u;%s%s\n", #name, (unsigned)(name), \
           (comment[0] ? "  --  " : ""), comment)

static void preamble(const char *target) {
    puts("------------------------------------------------------------------------------");
    puts("--                              Ada Web Server                              --");
    puts("--                                                                          --");
    puts("--                     Copyright (C) 2012-2025, AdaCore                     --");
    puts("------------------------------------------------------------------------------");
    puts("");
    puts("pragma Ada_2022;");
    puts("pragma Style_Checks (\"M32766\");");
    puts("--  Allow long lines");
    puts("");
    puts("--  This package provides target dependent definitions for the AWS library.");
    puts("--  Generated by vendor/aws-overlays/gen_os_lib.c — do not edit by hand.");
    printf("--  Target: %s\n", target);
    puts("");
    puts("with Interfaces.C.Strings;");
    puts("with System;");
    puts("with GNAT.OS_Lib;");
    puts("");
    puts("package OS_Lib is");
    puts("");
    puts("   use Interfaces;");
    puts("");
    puts("   type OS_Type is (Windows, VMS, Other_OS);");
    puts("   Target_OS                   : constant OS_Type := Other_OS;");
    puts("   pragma Warnings (Off, Target_OS);");
    printf("   Target_Name                 : constant String  := \"%s\";\n", target);
    puts("");
    puts("   Executable_Extension : constant String    := \"\";");
    puts("   Directory_Separator  : constant Character := '/';");
    puts("   Path_Separator       : constant Character := ':';");
    puts("");
}

int main(void) {
#if defined(__APPLE__) && defined(__aarch64__)
    const char *target = "darwin-arm64";
#elif defined(__APPLE__) && defined(__x86_64__)
    const char *target = "darwin-x86_64";
#elif defined(__linux__) && defined(__x86_64__)
    const char *target = "linux-x86_64";
#elif defined(__linux__) && defined(__aarch64__)
    const char *target = "linux-aarch64";
#else
    const char *target = "unknown";
#endif

    preamble(target);

    {
        struct sockaddr_in sa;
        struct pollfd v_pollfd;
        struct timeval tv;
        (void)sa; (void)v_pollfd; (void)tv;

        puts("   --  Sizes of various data types");
        puts("");
        printf("   SIZEOF_unsigned_int         : constant := %zu;\n", sizeof(unsigned int));
        printf("   SIZEOF_fd_set               : constant := %zu;\n", sizeof(fd_set));
        D(FD_SETSIZE, "Max fd value");
        printf("   SIZEOF_sin_family           : constant := %zu;\n", sizeof(sa.sin_family) * 8);
        printf("   SIN_FAMILY_OFFSET           : constant := %zu;\n",
               (size_t)((uintptr_t)&sa.sin_family - (uintptr_t)&sa));
        printf("   SIZEOF_nfds_t               : constant := %zu;\n", sizeof(nfds_t) * 8);
        printf("   SIZEOF_pollfd_events        : constant := %zu;\n", sizeof(v_pollfd.events) * 8);
        printf("   SIZEOF_fd_type              : constant := %zu;\n", sizeof(v_pollfd.fd) * 8);
        printf("   SIZEOF_socklen_t            : constant := %zu;\n", sizeof(socklen_t) * 8);
        printf("   SIZEOF_tv_sec               : constant := %zu;\n", sizeof(tv.tv_sec) * 8);
        printf("   SIZEOF_tv_usec              : constant := %zu;\n", sizeof(tv.tv_usec) * 8);
        puts("");
    }

    puts("   --  Poll values");
    D(POLLIN,    "There is data to read");
    D(POLLPRI,   "Urgent data to read");
    D(POLLOUT,   "Writing will not block");
    D(POLLERR,   "Error (output only)");
    D(POLLHUP,   "Hang up (output only)");
    D(POLLNVAL,  "Invalid request");
    puts("");

    puts("   --  Fcntl flags");
#ifndef FNDELAY
#define FNDELAY -1
#endif
    D(FNDELAY, "Nonblocking");
    puts("");

    puts("   --  Ioctl operations");
    D(FIONBIO,   "Set/clear non-blocking io");
    D(FIONREAD,  "How many bytes to read");
#ifdef SIOCOUTQ
    D(SIOCOUTQ,  "");
#define FIONWRITE_VAL SIOCOUTQ
#elif defined(TIOCOUTQ)
#define FIONWRITE_VAL TIOCOUTQ
#else
#define FIONWRITE_VAL -1
#endif
    printf("   %-27s : constant := %lu;\n", "FIONWRITE", (unsigned long)FIONWRITE_VAL);
    printf("   %-27s : constant := %d;\n", "FIONSPACE", -1);
    puts("");

    puts("   --  getaddrinfo / getnameinfo constants");
    D(AI_PASSIVE,     "NULL nodename for accepting");
    D(AI_CANONNAME,   "Get the host official name");
    D(AI_NUMERICSERV, "Service is a numeric string");
    D(AI_NUMERICHOST, "Node is a numeric IP address");
    D(EAI_SYSTEM,     "Check errno for details");
#ifdef EAI_NODATA
    D(EAI_NODATA,     "No address associated with nodename");
#else
    printf("   %-27s : constant := -1;\n", "EAI_NODATA");
#endif
    D(NI_NUMERICHOST, "Numeric form of the hostname");
    puts("");

    puts("   --  Errno values");
    D(EAGAIN,          "Try again");
    D(ENOENT,          "File not found");
    D(ENOMEM,          "Out of memory");
    D(EADDRNOTAVAIL,   "Cannot assign address");
    D(EINPROGRESS,     "Operation now in progress");
    D(EINTR,           "Interrupted system call");
    D(EINVAL,          "Invalid argument");
    D(ENAMETOOLONG,    "Name too long");
    D(ENOBUFS,         "No buffer space available");
    D(ENOTCONN,        "Socket not connected");
    D(ESHUTDOWN,       "Cannot send once shutdown");
    D(ESOCKTNOSUPPORT, "Socket type not supported");
    D(ETIMEDOUT,       "Connection timed out");
    D(ETOOMANYREFS,    "Too many references");
    D(EWOULDBLOCK,     "Operation would block");
    D(ECONNRESET,      "Connection reset by peer");
    D(EACCES,          "Permission denied");
    D(EADDRINUSE,      "Address already in use");
    D(EAFNOSUPPORT,    "Addr family not supported");
    D(EALREADY,        "Operation in progress");
    D(EBADF,           "Bad file descriptor");
    D(ECONNABORTED,    "Connection aborted");
    D(ECONNREFUSED,    "Connection refused");
    D(EDESTADDRREQ,    "Destination addr required");
    D(EFAULT,          "Bad address");
    D(EHOSTDOWN,       "Host is down");
    D(EHOSTUNREACH,    "No route to host");
    D(EIO,             "Input output error");
    D(EISCONN,         "Socket already connected");
    D(ELOOP,           "Too many symbolic links");
    D(EMFILE,          "Too many open files");
    D(EMSGSIZE,        "Message too long");
    D(EPIPE,           "Broken pipe");
    D(EPFNOSUPPORT,    "Unknown protocol family");
    D(EPROTONOSUPPORT, "Unknown protocol");
    D(EPROTOTYPE,      "Unknown protocol type");
    D(ENETDOWN,        "Network is down");
    D(ENETRESET,       "Disconn. on network reset");
    D(ENETUNREACH,     "Network is unreachable");
    D(ENOPROTOOPT,     "Protocol not available");
    D(ENOTSOCK,        "Operation on non socket");
    D(EOPNOTSUPP,      "Operation not supported");
    puts("");

    puts("   --  Address families");
    D(AF_INET,   "IPv4 address family");
    D(AF_INET6,  "IPv6 address family");
    D(AF_UNSPEC, "Unspecified address family");
    puts("");

    puts("   --  Socket modes");
    D(SOCK_STREAM, "Stream socket");
    D(SOCK_DGRAM,  "Datagram socket");
    puts("");

    puts("   --  Host errors");
    D(HOST_NOT_FOUND, "Unknown host");
    D(TRY_AGAIN,      "Host name lookup failure");
    D(NO_DATA,        "No data record for name");
    D(NO_RECOVERY,    "Non recoverable errors");
    puts("");

    puts("   --  Shutdown modes");
    D(SHUT_RD,   "No more recv");
    D(SHUT_WR,   "No more send");
    D(SHUT_RDWR, "No more recv/send");
    puts("");

    puts("   --  Protocol levels");
    D(SOL_SOCKET,    "Options for socket level");
    D(IPPROTO_IP,    "Dummy protocol for IP");
    D(IPPROTO_IPV6,  "IPv6 socket option level");
    D(IPPROTO_UDP,   "UDP");
    D(IPPROTO_TCP,   "TCP");
    puts("");

    puts("   --  Request flags");
    D(MSG_OOB,      "Process out-of-band data");
    D(MSG_PEEK,     "Peek at incoming data");
    D(MSG_EOR,      "Send end of record");
    D(MSG_WAITALL,  "Wait for full reception");
#ifdef MSG_NOSIGNAL
    D(MSG_NOSIGNAL, "No SIGPIPE on send");
#else
    printf("   %-27s : constant := -1;\n", "MSG_NOSIGNAL");
#endif
#ifdef __linux__
    puts("   MSG_Forced_Flags            : constant String := \"MSG_NOSIGNAL\";");
#else
    puts("   MSG_Forced_Flags            : constant String := \"0\";");
#endif
    puts("   --  Flags set on all send(2) calls");
    puts("");

    puts("   --  Socket options");
    D(TCP_NODELAY,        "Do not coalesce packets");
    D(SO_REUSEADDR,       "Bind reuse local address");
    D(SO_KEEPALIVE,       "Enable keep-alive msgs");
    D(SO_LINGER,          "Defer close to flush data");
    D(SO_BROADCAST,       "Can send broadcast msgs");
    D(SO_SNDBUF,          "Set/get send buffer size");
    D(SO_RCVBUF,          "Set/get recv buffer size");
    D(SO_SNDTIMEO,        "Emission timeout");
    D(SO_RCVTIMEO,        "Reception timeout");
    D(SO_ERROR,           "Get/clear error status");
    D(IP_MULTICAST_IF,    "Set/get mcast interface");
    D(IP_MULTICAST_TTL,   "Set/get multicast TTL");
    D(IP_MULTICAST_LOOP,  "Set/get mcast loopback");
    D(IP_ADD_MEMBERSHIP,  "Join a multicast group");
    D(IP_DROP_MEMBERSHIP, "Leave a multicast group");
#ifdef IP_PKTINFO
    D(IP_PKTINFO, "Get datagram info");
#elif defined(IP_RECVDSTADDR)
    printf("   %-27s : constant := %d;  --  Get datagram info\n", "IP_PKTINFO", IP_RECVDSTADDR);
#else
    printf("   %-27s : constant := -1;\n", "IP_PKTINFO");
#endif
    D(IPV6_V6ONLY, "Restricted to IPv6 communications only");
    puts("");

    puts("   --  Type definitions derived from sizes");
    puts("   type nfds_t is mod 2 ** SIZEOF_nfds_t;");
    puts("   for nfds_t'Size use SIZEOF_nfds_t;");
    puts("");
    puts("   type FD_Type");
    puts("     is range -(2 ** (SIZEOF_fd_type - 1)) .. 2 ** (SIZEOF_fd_type - 1) - 1;");
    puts("   for FD_Type'Size use SIZEOF_fd_type;");
    puts("");
    puts("   type Events_Type is mod 2 ** SIZEOF_pollfd_events;");
    puts("   for Events_Type'Size use SIZEOF_pollfd_events;");
    puts("");
    puts("   type socklen_t is mod 2 ** SIZEOF_socklen_t;");
    puts("   for socklen_t'Size use SIZEOF_socklen_t;");
    puts("");
    puts("   type timeval_tv_sec_t");
    puts("     is range -(2 ** (SIZEOF_tv_sec - 1)) .. 2 ** (SIZEOF_tv_sec - 1) - 1;");
    puts("   for timeval_tv_sec_t'Size use SIZEOF_tv_sec;");
    puts("");
    puts("   type timeval_tv_usec_t");
    puts("     is range -(2 ** (SIZEOF_tv_usec - 1)) .. 2 ** (SIZEOF_tv_usec - 1) - 1;");
    puts("   for timeval_tv_usec_t'Size use SIZEOF_tv_usec;");
    puts("");
    puts("   type Timeval is record");
    puts("      tv_sec  : timeval_tv_sec_t;  -- Seconds");
    puts("      tv_usec : timeval_tv_usec_t; -- Microseconds");
    puts("   end record;");
    puts("   pragma Convention (C, Timeval);");
    puts("");
    puts("   type sa_family_t is mod 2 ** SIZEOF_sin_family;");
    puts("   for sa_family_t'Size use SIZEOF_sin_family;");
    puts("");
    puts("   type In6_Addr is array (1 .. 8) of Interfaces.Unsigned_16;");
    puts("   pragma Convention (C, In6_Addr);");
    puts("");
    puts("   type Sockaddr_In6 is record");

    {
        struct sockaddr_in sa;
        size_t fam_off = (size_t)((uintptr_t)&sa.sin_family - (uintptr_t)&sa);
        if (fam_off == 1) {
            puts("      Length   : Interfaces.Unsigned_8 := 0;");
        }
    }
    puts("      Family   : sa_family_t := 0;");
    puts("      Port     : Interfaces.C.unsigned_short := 0;");
    puts("      FlowInfo : Interfaces.Unsigned_32 := 0;");
    puts("      Addr     : In6_Addr := [others => 0];");
    puts("      Scope_Id : Interfaces.Unsigned_32 := 0;");
    puts("   end record;");
    puts("   pragma Convention (C, Sockaddr_In6);");
    puts("");
    puts("   type Addr_Info;");
    puts("   type Addr_Info_Access is access all Addr_Info;");
    puts("");
    puts("   type Addr_Info is record");
    puts("      ai_flags     : C.int;");
    puts("      ai_family    : C.int;");
    puts("      ai_socktype  : C.int;");
    puts("      ai_protocol  : C.int;");
    puts("      ai_addrlen   : socklen_t;");

    {
        struct addrinfo ai;
        size_t can_off  = (size_t)((uintptr_t)&ai.ai_canonname - (uintptr_t)&ai);
        size_t addr_off = (size_t)((uintptr_t)&ai.ai_addr      - (uintptr_t)&ai);
        if (can_off < addr_off) {
            puts("      ai_canonname : C.Strings.chars_ptr;");
            puts("      ai_addr      : System.Address;");
        } else {
            puts("      ai_addr      : System.Address;");
            puts("      ai_canonname : C.Strings.chars_ptr;");
        }
    }
    puts("      ai_next      : Addr_Info_Access;");
    puts("   end record;");
    puts("   pragma Convention (C, Addr_Info);");
    puts("");
    puts("   function GetAddrInfo");
    puts("     (node    : C.Strings.chars_ptr;");
    puts("      service : C.Strings.chars_ptr;");
    puts("      hints   : Addr_Info;");
    puts("      res     : not null access Addr_Info_Access) return C.int;");
    puts("");
    puts("   procedure FreeAddrInfo (res : Addr_Info_Access);");
    puts("");
    puts("   function GAI_StrError (ecode : C.int) return C.Strings.chars_ptr;");
    puts("   function Socket_StrError (ecode : Integer) return C.Strings.chars_ptr;");
    puts("");
    puts("   function Set_Sock_Opt");
    puts("     (S       : C.int;");
    puts("      Level   : C.int;");
    puts("      OptName : C.int;");
    puts("      OptVal  : System.Address;");
    puts("      OptLen  : C.int) return C.int;");
    puts("");
    puts("   function C_Ioctl (S : C.int; Req : C.int; Arg : access C.int) return C.int;");
    puts("   function C_Close (Fd : C.int) return C.int;");
    puts("");
    puts("   procedure WSA_Startup (Version : C.int; Data : System.Address) is null;");
    puts("   function Socket_Errno return Integer renames GNAT.OS_Lib.Errno;");
    puts("");
    puts("private");
    puts("");
    puts("   pragma Import (C, GetAddrInfo, \"getaddrinfo\");");
    puts("   pragma Import (C, FreeAddrInfo, \"freeaddrinfo\");");
    puts("   pragma Import (C, Set_Sock_Opt, \"setsockopt\");");
    puts("   pragma Import (C, GAI_StrError, \"gai_strerror\");");
    puts("   pragma Import (C, Socket_StrError, \"strerror\");");
    puts("   pragma Import (C, C_Ioctl, \"ioctl\");");
    puts("   pragma Import (C, C_Close, \"close\");");
    puts("");
    puts("end OS_Lib;");

    return 0;
}
